import okhttp3.OkHttpClient;
import retrofit2.Retrofit;
import retrofit2.converter.gson.GsonConverterFactory;

public class ApiService {
    private static final String BASE_URL_DEVELOPMENT = "https://api.example.com/";
    private static final String BASE_URL_STAGING = "https://staging.api.example.com/";
    private static final String BASE_URL_PRODUCTION = "https://production.api.example.com/";

    public enum Environment {
        DEVELOPMENT,
        STAGING,
        PRODUCTION
    }

    private static Retrofit retrofit;

    public static void init(Environment environment) {
        OkHttpClient client = new OkHttpClient.Builder().build();

        String baseUrl;
        switch (environment) {
            case DEVELOPMENT:
                baseUrl = BASE_URL_DEVELOPMENT;
                break;
            case STAGING:
                baseUrl = BASE_URL_STAGING;
                break;
            case PRODUCTION:
                baseUrl = BASE_URL_PRODUCTION;
                break;
            default:
                throw new IllegalArgumentException("Unknown environment");
        }

        retrofit = new Retrofit.Builder()
                .baseUrl(baseUrl)
                .addConverterFactory(GsonConverterFactory.create())
                .client(client)
                .build();
    }

    public static UserApi getUserApi() {
        if (retrofit == null) {
            throw new IllegalStateException("ApiService not initialized. Call init() first.");
        }
        return retrofit.create(UserApi.class);
    }
}

